DROP TABLE user_topic_progresses;

CREATE TABLE enrollments (
    user_id UUID NOT NULL,
    course_id UUID NOT NULL,
    enrolled_at TIMESTAMPTZ NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_enrollments PRIMARY KEY (user_id, course_id),
    CONSTRAINT fk_enrollments_user_id FOREIGN KEY (user_id) REFERENCES users(user_id),
    CONSTRAINT fk_enrollments_course_id FOREIGN KEY (course_id) REFERENCES courses(course_id)
);

CREATE INDEX idx_enrollments_course_id ON enrollments USING BTREE (course_id);

CREATE TRIGGER trigger_enrollments_meta_updated_at BEFORE
UPDATE
    ON enrollments FOR EACH ROW EXECUTE FUNCTION update_meta_updated_at();

CREATE TABLE topic_progresses (
    user_id UUID NOT NULL,
    course_id UUID NOT NULL,
    course_section_topic_id UUID NOT NULL,
    status TEXT NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_topic_progresses PRIMARY KEY (user_id, course_id, course_section_topic_id),
    CONSTRAINT fk_topic_progresses_enrollment FOREIGN KEY (user_id, course_id) REFERENCES enrollments(user_id, course_id),
    CONSTRAINT fk_topic_progresses_course_section_topic_id FOREIGN KEY (course_section_topic_id) REFERENCES course_section_topics(course_section_topic_id)
);

COMMENT ON COLUMN topic_progresses.status IS 'IN_PROGRESS = 開始済み, COMPLETED = 完了済み, 開始していない場合はレコード自体がないので値として持たない';

CREATE INDEX idx_topic_progresses_course_section_topic_id ON topic_progresses USING BTREE (course_section_topic_id);

CREATE TRIGGER trigger_topic_progresses_meta_updated_at BEFORE
UPDATE
    ON topic_progresses FOR EACH ROW EXECUTE FUNCTION update_meta_updated_at();

CREATE EXTENSION ltree;

CREATE FUNCTION update_meta_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW._updated_at := NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TABLE categories (
    category_id UUID,
    name TEXT NOT NULL,
    path ltree NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_categories PRIMARY KEY (category_id)
);

CREATE INDEX idx_categories_path ON categories USING gist (path);

CREATE TABLE authors (
    author_id UUID,
    name TEXT NOT NULL,
    profile TEXT NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_authors PRIMARY KEY (author_id)
);

CREATE TABLE courses (
    course_id UUID,
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    slug TEXT NOT NULL,
    tags JSONB NOT NULL,
    publish_status TEXT NOT NULL,
    category_id UUID NOT NULL,
    published_at TIMESTAMPTZ,
    author_id UUID NOT NULL,
    visibility TEXT NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_courses PRIMARY KEY (course_id),
    CONSTRAINT fk_courses_category_id FOREIGN KEY (category_id) REFERENCES categories(category_id),
    CONSTRAINT fk_courses_author_id FOREIGN KEY (author_id) REFERENCES authors(author_id),
    CONSTRAINT uq_courses_slug_author_id UNIQUE (slug, author_id)
);

CREATE INDEX idx_courses_category_id ON courses USING btree (category_id);
CREATE INDEX idx_courses_author_id ON courses USING btree (author_id);
CREATE INDEX idx_courses_tags ON courses USING gin (tags);

COMMENT ON COLUMN courses.publish_status IS 'draft / published / archived';
COMMENT ON COLUMN courses.visibility IS 'private = 自分のみ, public = 誰でも閲覧可, paid = 購入者のみ';

CREATE TRIGGER trigger_courses_meta_updated_at
    BEFORE UPDATE ON courses
    FOR EACH ROW
    EXECUTE FUNCTION update_meta_updated_at();

CREATE TRIGGER trigger_categories_meta_updated_at
    BEFORE UPDATE ON categories
    FOR EACH ROW
    EXECUTE FUNCTION update_meta_updated_at();

CREATE TRIGGER trigger_authors_meta_updated_at
    BEFORE UPDATE ON authors
    FOR EACH ROW
    EXECUTE FUNCTION update_meta_updated_at();

package commands

import (
	"encoding/json"
	"errors"
	"log"
	"net/http"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
	"github.com/jackc/pgx/v5"
)

const (
	errorCodeEnrollmentForbidden = "ENROLLMENT_FORBIDDEN"
	errorCodeCourseNotFound      = "COURSE_NOT_FOUND"
	errorCodeTopicNotFound       = "TOPIC_NOT_FOUND"
	errorCodeNotEnrolled         = "NOT_ENROLLED"
)

type UpdateEnrollmentHandler struct {
	usecase UpdateEnrollmentUsecaseInterface
}

func NewUpdateEnrollmentHandler(usecase UpdateEnrollmentUsecaseInterface) *UpdateEnrollmentHandler {
	return &UpdateEnrollmentHandler{usecase: usecase}
}

type patchEnrollmentRequestBody struct {
	TopicId string `json:"topicId"`
	Status  string `json:"status"`
}

type patchEnrollmentResponse struct {
	TopicId string `json:"topicId"`
	Status  string `json:"status"`
}

func (h *UpdateEnrollmentHandler) PatchEnrollmentHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	userIdStr := r.PathValue("userID")
	if userIdStr == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be required")
		return
	}
	userId, err := uuid.Parse(userIdStr)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be UUID format")
		return
	}

	courseIdStr := r.PathValue("courseId")
	if courseIdStr == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "courseId must be required")
		return
	}
	courseId, err := uuid.Parse(courseIdStr)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "courseId must be UUID format")
		return
	}

	var body patchEnrollmentRequestBody
	defer r.Body.Close()
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "body parameter is invalid json format")
		return
	}

	if body.TopicId == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "topicId must be required")
		return
	}
	topicId, err := uuid.Parse(body.TopicId)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "topicId must be UUID format")
		return
	}

	if body.Status == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "status must be required")
		return
	}
	status := ProgressStatus(body.Status)
	if status != ProgressStatusInProgress && status != ProgressStatusCompleted {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "status must be IN_PROGRESS or COMPLETED")
		return
	}

	result, err := h.usecase.execute(r.Context(), UpdateEnrollmentParams{
		userId:   userId,
		courseId: courseId,
		topicId:  topicId,
		status:   status,
	})
	if err != nil {
		switch {
		case errors.Is(err, ErrInvalidProgressStatus), errors.Is(err, ErrInvalidStatusTransit):
			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, err.Error())
		case errors.Is(err, pgx.ErrNoRows):
			response.WriteErrorResponse(w, http.StatusNotFound, errorCodeCourseNotFound, "course not found")
		case errors.Is(err, ErrTopicNotFoundInCourse):
			response.WriteErrorResponse(w, http.StatusNotFound, errorCodeTopicNotFound, "topic not found in course")
		case errors.Is(err, ErrNotEnrolled):
			response.WriteErrorResponse(w, http.StatusNotFound, errorCodeNotEnrolled, "not enrolled in this course")
		default:
			log.Printf("PatchEnrollmentHandler error: %v", err)
			response.WriteInternalServerErrorResponse(w)
		}
		return
	}

	w.WriteHeader(http.StatusOK)
	_ = json.NewEncoder(w).Encode(patchEnrollmentResponse{
		TopicId: result.TopicId,
		Status:  result.Status,
	})
}

