// Package main は学習コンテンツ（コース・セクション・トピック）を DB に投入する seed コマンド。
//
// 仕様:
//   - data/courses/<course-slug>/course.yaml をエントリポイントとし、配下の topics/*.md を読み込む
//   - course / author / category / section / topic それぞれは決定的 UUID を持ち、再実行で同一行を更新する
//   - section と topic は再投入のたびに削除→再挿入する（順序や数の変更を反映するため）
//
// 環境変数:
//   - DATABASE_URL: 接続先 (必須)
//   - SEED_DATA_DIR: data ディレクトリのパス (省略時は cmd/seed/data)
package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"gopkg.in/yaml.v3"
)

// seedNamespace は決定的 UUID 生成のための固定ルート namespace。
// 値を変更すると既存 seed データとは別系統になり、再投入時に新規行として挿入されるので注意。
var seedNamespace = uuid.MustParse("a0a0a0a0-1111-4111-8111-000000000001")

type courseYaml struct {
	Title         string        `yaml:"title"`
	Description   string        `yaml:"description"`
	Slug          string        `yaml:"slug"`
	Tags          []string      `yaml:"tags"`
	PublishStatus string        `yaml:"publishStatus"`
	Visibility    string        `yaml:"visibility"`
	AuthorName    string        `yaml:"authorName"`
	AuthorProfile string        `yaml:"authorProfile"`
	CategoryName  string        `yaml:"categoryName"`
	CategoryPath  string        `yaml:"categoryPath"`
	Sections      []sectionYaml `yaml:"sections"`
}

type sectionYaml struct {
	Title       string      `yaml:"title"`
	Description string      `yaml:"description"`
	Topics      []topicYaml `yaml:"topics"`
}

type topicYaml struct {
	File string `yaml:"file"`
}

type topicMeta struct {
	Title       string `yaml:"title"`
	Description string `yaml:"description"`
}

func main() {
	ctx := context.Background()

	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		log.Fatal("DATABASE_URL is required")
	}

	dataDir := os.Getenv("SEED_DATA_DIR")
	if dataDir == "" {
		dataDir = filepath.Join("cmd", "seed", "data")
	}
	coursesDir := filepath.Join(dataDir, "courses")

	entries, err := os.ReadDir(coursesDir)
	if err != nil {
		log.Fatalf("read courses dir %s: %v", coursesDir, err)
	}

	conn, err := pgx.Connect(ctx, dbURL)
	if err != nil {
		log.Fatalf("connect db: %v", err)
	}
	defer conn.Close(ctx)

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		courseDir := filepath.Join(coursesDir, entry.Name())
		if err := seedCourse(ctx, conn, courseDir); err != nil {
			log.Fatalf("seed course %s: %v", entry.Name(), err)
		}
	}

	log.Println("seed: completed")
}

func seedCourse(ctx context.Context, conn *pgx.Conn, courseDir string) error {
	yamlPath := filepath.Join(courseDir, "course.yaml")
	raw, err := os.ReadFile(yamlPath)
	if err != nil {
		return fmt.Errorf("read course.yaml: %w", err)
	}

	var course courseYaml
	if err := yaml.Unmarshal(raw, &course); err != nil {
		return fmt.Errorf("parse course.yaml: %w", err)
	}

	authorID := deterministicUUID("author", course.AuthorName)
	categoryID := deterministicUUID("category", course.CategoryName)
	courseID := deterministicUUID("course", course.Slug)

	tx, err := conn.Begin(ctx)
	if err != nil {
		return err
	}
	defer func() { _ = tx.Rollback(ctx) }()

	if _, err := tx.Exec(ctx, `
		INSERT INTO authors (author_id, name, profile)
		VALUES ($1, $2, $3)
		ON CONFLICT (author_id) DO UPDATE SET
			name = EXCLUDED.name,
			profile = EXCLUDED.profile
	`, authorID, course.AuthorName, course.AuthorProfile); err != nil {
		return fmt.Errorf("upsert author: %w", err)
	}

	if _, err := tx.Exec(ctx, `
		INSERT INTO categories (category_id, name, path)
		VALUES ($1, $2, $3::ltree)
		ON CONFLICT (category_id) DO UPDATE SET
			name = EXCLUDED.name,
			path = EXCLUDED.path
	`, categoryID, course.CategoryName, course.CategoryPath); err != nil {
		return fmt.Errorf("upsert category: %w", err)
	}

	tagsJSON, err := json.Marshal(course.Tags)
	if err != nil {
		return fmt.Errorf("marshal tags: %w", err)
	}

	publishedAt := time.Now().UTC()
	if _, err := tx.Exec(ctx, `
		INSERT INTO courses (
			course_id, title, description, slug, tags, publish_status,
			category_id, published_at, author_id, visibility
		)
		VALUES ($1, $2, $3, $4, $5::jsonb, $6, $7, $8, $9, $10)
		ON CONFLICT (course_id) DO UPDATE SET
			title = EXCLUDED.title,
			description = EXCLUDED.description,
			slug = EXCLUDED.slug,
			tags = EXCLUDED.tags,
			publish_status = EXCLUDED.publish_status,
			category_id = EXCLUDED.category_id,
			published_at = EXCLUDED.published_at,
			visibility = EXCLUDED.visibility
	`, courseID, course.Title, course.Description, course.Slug, tagsJSON, course.PublishStatus,
		categoryID, publishedAt, authorID, course.Visibility); err != nil {
		return fmt.Errorf("upsert course: %w", err)
	}

	if _, err := tx.Exec(ctx, `
		DELETE FROM topic_progresses
		WHERE course_section_topic_id IN (
			SELECT course_section_topic_id FROM course_section_topics WHERE course_id = $1
		)
	`, courseID); err != nil {
		return fmt.Errorf("delete topic_progresses: %w", err)
	}
	if _, err := tx.Exec(ctx, `DELETE FROM course_section_topics WHERE course_id = $1`, courseID); err != nil {
		return fmt.Errorf("delete topics: %w", err)
	}
	if _, err := tx.Exec(ctx, `DELETE FROM course_sections WHERE course_id = $1`, courseID); err != nil {
		return fmt.Errorf("delete sections: %w", err)
	}

	for sIdx, section := range course.Sections {
		sectionID := deterministicUUID("section:"+course.Slug, fmt.Sprintf("%d", sIdx+1))

		if _, err := tx.Exec(ctx, `
			INSERT INTO course_sections (course_section_id, course_id, index, title, description)
			VALUES ($1, $2, $3, $4, $5)
		`, sectionID, courseID, sIdx+1, section.Title, section.Description); err != nil {
			return fmt.Errorf("insert section %d: %w", sIdx+1, err)
		}

		for tIdx, topic := range section.Topics {
			topicID := deterministicUUID(
				fmt.Sprintf("topic:%s:%d", course.Slug, sIdx+1),
				fmt.Sprintf("%d", tIdx+1),
			)

			mdPath := filepath.Join(courseDir, "topics", topic.File)
			mdRaw, err := os.ReadFile(mdPath)
			if err != nil {
				return fmt.Errorf("read topic %s: %w", topic.File, err)
			}
			meta, body, err := parseFrontmatter(mdRaw)
			if err != nil {
				return fmt.Errorf("parse topic %s: %w", topic.File, err)
			}

			if _, err := tx.Exec(ctx, `
				INSERT INTO course_section_topics (
					course_section_topic_id, course_id, course_section_id,
					index, title, description, content
				)
				VALUES ($1, $2, $3, $4, $5, $6, $7)
			`, topicID, courseID, sectionID, tIdx+1, meta.Title, meta.Description, body); err != nil {
				return fmt.Errorf("insert topic %s: %w", topic.File, err)
			}
		}
	}

	if err := tx.Commit(ctx); err != nil {
		return fmt.Errorf("commit: %w", err)
	}

	log.Printf("seed: course %q (%s) inserted with %d sections", course.Title, courseID, len(course.Sections))
	return nil
}

// deterministicUUID は scope と key の組から決定的に UUID を生成する。
// 同じ scope+key からは常に同じ UUID が得られるため、再実行時に同一行を upsert できる。
func deterministicUUID(scope, key string) uuid.UUID {
	ns := uuid.NewMD5(seedNamespace, []byte(scope))
	return uuid.NewMD5(ns, []byte(key))
}

// parseFrontmatter は --- で区切られた YAML フロントマター付き Markdown を分解する。
// 先頭が `---\n` で始まり、続く `\n---\n` で閉じられている形式のみを受け付ける。
func parseFrontmatter(raw []byte) (topicMeta, string, error) {
	text := strings.ReplaceAll(string(raw), "\r\n", "\n")
	if !strings.HasPrefix(text, "---\n") {
		return topicMeta{}, "", errors.New("missing frontmatter opener")
	}
	rest := strings.TrimPrefix(text, "---\n")

	closeIdx := strings.Index(rest, "\n---\n")
	if closeIdx < 0 {
		return topicMeta{}, "", errors.New("missing frontmatter closer")
	}

	fmText := rest[:closeIdx]
	body := strings.TrimLeft(rest[closeIdx+len("\n---\n"):], "\n")

	var meta topicMeta
	if err := yaml.Unmarshal([]byte(fmText), &meta); err != nil {
		return topicMeta{}, "", fmt.Errorf("unmarshal frontmatter: %w", err)
	}
	return meta, body, nil
}

